{"code": "import json
import re

# Read business data file
file_path = '/tmp/tmpt_7l_70r.json'
with open(file_path, 'r') as f:
    business_data = json.load(f)

# Read ratings data
ratings_data = locals()['var_functions.query_db:16']

# Create ratings dictionary
ratings_dict = {}
for item in ratings_data:
    ratings_dict[item['gmap_id']] = float(item['avg_rating'])

# Function to check if business is open after 6PM
def check_open_after_6pm(hours_str):
    if not hours_str or hours_str == 'None':
        return False

    try:
        hours_list = eval(hours_str)
        if not isinstance(hours_list, list):
            return False

        weekdays = ['Monday', 'Tuesday', 'Wednesday', 'Thursday', 'Friday']

        for entry in hours_list:
            if len(entry) != 2:
                continue

            day, time_range = entry
            if day not in weekdays:
                continue

            if time_range == 'Open 24 hours':
                return True
            if time_range == 'Closed':
                continue

            # Extract closing time
            dash_pos = max(time_range.find('-'), time_range.find('\u2013'), time_range.find('\u2014'))
            if dash_pos == -1:
                continue

            closing_str = time_range[dash_pos + 1:].strip()

            # Parse time
            if 'PM' in closing_str.upper():
                # Extract hour number
                num_match = re.search(r'(\d{1,2})', closing_str)
                if num_match:
                    hour = int(num_match.group(1))
                    if hour < 12:  # Convert PM to 24-hour
                        hour += 12
                    if hour > 18:  # After 6 PM
                        return True

        return False
    except:
        return False

# Find businesses open after 6PM
open_late = []
for business in business_data:
    gmap_id = business.get('gmap_id')
    hours = business.get('hours')

    if not hours or hours == 'None':
        continue

    if check_open_after_6pm(hours):
        avg_rating = ratings_dict.get(gmap_id, 0.0)
        open_late.append({
            'name': business['name'],
            'gmap_id': gmap_id,
            'hours': hours,
            'avg_rating': avg_rating
        })

# Sort by rating and get top 5
open_late.sort(key=lambda x: x['avg_rating'], reverse=True)
top_5 = open_late[:5]

# Format output
result = []
for i, biz in enumerate(top_5, 1):
    result.append({
        'rank': i,
        'name': biz['name'],
        'hours': biz['hours'],
        'avg_rating': round(biz['avg_rating'], 2)
    })

print('__RESULT__:')
print(json.dumps(result))"}

